<?php require_once __DIR__.'/includes/functions.php'; require_login(); $id=(int)($_GET['id']??0); $st=db()->prepare('SELECT e.*,s.name subject_name FROM exams e JOIN subjects s ON s.id=e.subject_id WHERE e.id=?');$st->execute([$id]);$exam=$st->fetch();$st=db()->prepare('SELECT q.*,eq.position FROM exam_questions eq JOIN questions q ON q.id=eq.question_id WHERE eq.exam_id=? ORDER BY eq.position');$st->execute([$id]);$qs=$st->fetchAll(); header('Content-Type: application/msword; charset=utf-8'); header('Content-Disposition: attachment; filename="dap-an-'.$id.'.doc"'); ?><html><meta charset="utf-8"><body><h1>ĐÁP ÁN ĐỀ <?= e($exam['code']??'') ?></h1><p>Môn: <?= e($exam['subject_name']??'') ?></p><?php $i=1; foreach($qs as $q): ?><p><strong>Câu <?= $i++ ?>:</strong> <?= e($q['answer']) ?></p><?php endforeach; ?></body></html>
